import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { FaArrowLeft, FaThumbsUp, FaRegThumbsUp, FaBookmark, FaRegBookmark, FaShare, FaTrash } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';
import CommentForm from '../components/CommentForm';
import CommentItem from '../components/CommentItem';
import Spinner from '../components/Spinner';
import forumService from '../services/forumService';
import { formatDistanceToNow } from 'date-fns';

const PostDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  
  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmittingComment, setIsSubmittingComment] = useState(false);
  const [isLiked, setIsLiked] = useState(false);
  const [isBookmarked, setIsBookmarked] = useState(false);

  useEffect(() => {
    const fetchPostDetails = async () => {
      try {
        setIsLoading(true);
        const data = await forumService.getPostById(id);
        setPost(data);
        setComments(data.comments);
        
        if (user) {
          setIsLiked(data.likes?.includes(user._id));
          const bookmarkCheck = await forumService.checkBookmark(id);
          setIsBookmarked(bookmarkCheck.isBookmarked);
        }
      } catch (error) {
        console.error('Error fetching post:', error);
        toast.error('Failed to load post details');
        navigate('/forum');
      } finally {
        setIsLoading(false);
      }
    };

    fetchPostDetails();
  }, [id, user, navigate]);

  const handleCommentSubmit = async (text) => {
    if (!user) {
      toast.error('Please log in to comment');
      return;
    }

    try {
      setIsSubmittingComment(true);
      const newComment = await forumService.addComment(id, { text });
      setComments([...comments, newComment]);
      toast.success('Comment added successfully');
      return true;
    } catch (error) {
      console.error('Error adding comment:', error);
      toast.error('Failed to add comment');
      return false;
    } finally {
      setIsSubmittingComment(false);
    }
  };

  const handleDeleteComment = (commentId) => {
    setComments(comments.filter(comment => comment._id !== commentId));
  };

  const handleLike = async () => {
    if (!user) {
      toast.error('Please log in to like posts');
      return;
    }

    try {
      await forumService.likePost(id);
      setIsLiked(!isLiked);
      setPost({
        ...post,
        likes: isLiked 
          ? post.likes.filter(likeId => likeId !== user._id) 
          : [...post.likes, user._id]
      });
    } catch (error) {
      console.error('Error liking post:', error);
      toast.error('Failed to like post');
    }
  };

  const handleBookmark = async () => {
    if (!user) {
      toast.error('Please log in to bookmark posts');
      return;
    }

    try {
      await forumService.bookmarkPost(id);
      setIsBookmarked(!isBookmarked);
      toast.success(isBookmarked ? 'Post removed from bookmarks' : 'Post bookmarked successfully');
    } catch (error) {
      console.error('Error bookmarking post:', error);
      toast.error('Failed to bookmark post');
    }
  };

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href);
    toast.success('Link copied to clipboard');
  };

  const handleDeletePost = async () => {
    if (!user || (user._id !== post.user._id && !user.isAdmin)) {
      toast.error('You are not authorized to delete this post');
      return;
    }

    if (window.confirm('Are you sure you want to delete this post? This action cannot be undone.')) {
      try {
        await forumService.deletePost(id);
        toast.success('Post deleted successfully');
        navigate('/forum');
      } catch (error) {
        console.error('Error deleting post:', error);
        toast.error('Failed to delete post');
      }
    }
  };

  if (isLoading) {
    return <Spinner />;
  }

  if (!post) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="text-center py-12">
          <h2 className="text-xl font-semibold text-gray-800 dark:text-gray-200 mb-4">Post not found</h2>
          <Link to="/forum" className="text-green-600 hover:text-green-800 dark:text-green-400 dark:hover:text-green-300">
            Return to Forums
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <Link 
        to="/forum" 
        className="flex items-center text-green-600 hover:text-green-800 dark:text-green-400 dark:hover:text-green-300 mb-6"
      >
        <FaArrowLeft className="mr-2" />
        Back to Forums
      </Link>
      
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-md overflow-hidden">
        {/* Post header */}
        <div className="p-6 border-b dark:border-gray-700">
          <div className="flex justify-between items-start">
            <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">{post.title}</h1>
            
            {user && (user._id === post.user._id || user.isAdmin) && (
              <button 
                onClick={handleDeletePost} 
                className="text-red-500 hover:text-red-700 dark:hover:text-red-400 p-1"
                aria-label="Delete post"
              >
                <FaTrash />
              </button>
            )}
          </div>
          
          <div className="flex items-center mb-4">
            <div className="h-10 w-10 rounded-full bg-green-500 flex items-center justify-center text-white font-semibold mr-3">
              {post.user.name.charAt(0).toUpperCase()}
            </div>
            <div>
              <p className="font-medium text-gray-900 dark:text-white">{post.user.name}</p>
              <p className="text-sm text-gray-500 dark:text-gray-400">
                {formatDistanceToNow(new Date(post.createdAt), { addSuffix: true })}
              </p>
            </div>
          </div>
          
          <div className="mb-4">
            <span className="inline-block px-3 py-1 bg-green-100 text-green-800 dark:bg-green-800 dark:text-green-100 rounded-full text-sm font-medium">
              {post.category}
            </span>
          </div>
          
          <div className="prose max-w-none dark:prose-invert mb-6">
            <p className="text-gray-700 dark:text-gray-300 whitespace-pre-line">{post.description}</p>
          </div>
          
          <div className="flex items-center justify-between pt-4">
            <div className="flex items-center space-x-4">
              <button 
                onClick={handleLike} 
                className="flex items-center text-gray-600 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400"
              >
                {isLiked ? (
                  <FaThumbsUp className="text-blue-600 dark:text-blue-400 mr-1" />
                ) : (
                  <FaRegThumbsUp className="mr-1" />
                )}
                <span>{post.likes ? post.likes.length : 0}</span>
              </button>
              
              <button 
                onClick={handleBookmark} 
                className="flex items-center text-gray-600 dark:text-gray-400 hover:text-yellow-600 dark:hover:text-yellow-400"
              >
                {isBookmarked ? (
                  <FaBookmark className="text-yellow-600 dark:text-yellow-400 mr-1" />
                ) : (
                  <FaRegBookmark className="mr-1" />
                )}
                <span>Save</span>
              </button>
              
              <button 
                onClick={handleShare} 
                className="flex items-center text-gray-600 dark:text-gray-400 hover:text-green-600 dark:hover:text-green-400"
              >
                <FaShare className="mr-1" />
                <span>Share</span>
              </button>
            </div>
            
            <div className="text-gray-500 dark:text-gray-400 text-sm">
              {comments.length} {comments.length === 1 ? 'comment' : 'comments'}
            </div>
          </div>
        </div>
        
        {/* Comments section */}
        <div className="p-6">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">Comments</h2>
          
          <CommentForm 
            onSubmit={handleCommentSubmit} 
            isSubmitting={isSubmittingComment} 
          />
          
          <div className="mt-8">
            {comments.length > 0 ? (
              comments.map(comment => (
                <CommentItem
                  key={comment._id}
                  comment={comment}
                  postId={id}
                  onDeleteComment={handleDeleteComment}
                />
              ))
            ) : (
              <div className="text-center py-8 text-gray-500 dark:text-gray-400">
                <p>No comments yet. Be the first to comment!</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PostDetail;
